import{_ as t,o as a,c as r,a2 as s}from"./chunks/framework.C7GIOALF.js";const u=JSON.parse('{"title":"Formats","description":"","frontmatter":{},"headers":[],"relativePath":"formats/index.md","filePath":"formats/index.md","lastUpdated":1782031805000}'),d={name:"formats/index.md"};function o(n,e,i,c,m,h){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="formats" tabindex="-1">Formats <a class="header-anchor" href="#formats" aria-label="Permalink to &quot;Formats&quot;">​</a></h1><p>Formats are the rulesets or play structures that can support a game night. Some are broad families, while others are specific variants with their own setup and components.</p><h2 id="current-formats" tabindex="-1">Current Formats <a class="header-anchor" href="#current-formats" aria-label="Permalink to &quot;Current Formats&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>Brief</th><th>Sub variants / notes</th></tr></thead><tbody><tr><td><a href="./bang-like/">BANG-like hidden role formats</a></td><td>Secret-role multiplayer formats built around a public leader, hidden allies, attackers, and solo chaos roles.</td><td>Kingdoms, BANG EDH / Kingdom-Bang EDH, BANG! Magic, MTG Treachery, and the <a href="./../boxed-sets/feudalism.html">Feudalism</a> boxed-set concept.</td></tr><tr><td><a href="./big-deck/">Big Deck</a></td><td>Shared-library and large communal-pool formats for chaotic, low-prep games.</td><td><a href="./big-deck/pile-o-magic/">Pile o&#39; Magic</a> is the local formalized version with Heap Lands and Commander options.</td></tr><tr><td><a href="./creature-feature/">Creature Feature</a></td><td>Pegasus Loft 60-card constructed format with creature-density and shared creature-type deck-building rules.</td><td>Event knobs include temporary bans for winning creature types and a ban on negative creature-type hate.</td></tr><tr><td><a href="./cube/">Cube</a></td><td>Reusable draft environments built from a curated card pool instead of retail boosters.</td><td>Common forms include powered, unpowered, peasant, pauper, set, theme, and Commander cubes, plus alternate draft methods.</td></tr><tr><td><a href="./assassin/">Assassin</a></td><td>Target-assignment formats where each player receives a secret mark or quarry.</td><td><a href="./assassin/variants/hitmen.html">Hitmen</a> is the local Pegasus Loft variant with constrained attacking and targeting.</td></tr><tr><td><a href="./archenemy/">Archenemy</a></td><td>One-villain-versus-the-table formats where the archenemy uses a scheme deck.</td><td>Standard Archenemy uses 60-card decks; Archenemy Commander turns the structure into a Commander boss fight.</td></tr><tr><td><a href="./horde/">Horde</a></td><td>Cooperative player team versus an automated enemy deck that casts waves of threats.</td><td>Tracks Classic Zombie Horde, HordeMagic.com EDH-style rules, Raid-style staged decks, and survivor or companion-deck versions.</td></tr></tbody></table>',4)])])}const f=t(d,[["render",o]]);export{u as __pageData,f as default};
